/* global Excel */

import { activePalette } from "../core/style";
import { BindingRegistry, RegisteredBinding } from "../core/bindings";
import { RangeSnapshot } from "../core/data";

interface Task {
  name: string;
  start: number;
  end: number;
}

function toDate(v: unknown): number | null {
  if (v == null || v === "") return null;
  if (typeof v === "number") {
    if (v > 1 && v < 80000) {
      return new Date(Date.UTC(1899, 11, 30) + v * 86400000).getTime();
    }
    return null;
  }
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : null;
}

export async function insertGantt(): Promise<void> {
  const palette = activePalette();
  await Excel.run(async (ctx) => {
    const sel = ctx.workbook.getSelectedRange();
    sel.load(["values","rowCount","columnCount","address","rowIndex","columnIndex","worksheet/name"]);
    await ctx.sync();

    if (sel.columnCount < 3) throw new Error("Select 3 columns: Task, Start, End-or-Duration.");
    if (sel.rowCount < 2) throw new Error("Gantt needs at least one row of task data.");

    const tasks: Task[] = [];
    for (let r = 1; r < sel.rowCount; r++) {
      const row = sel.values[r];
      const name = String(row[0] ?? "");
      const start = toDate(row[1]);
      if (start === null) continue;
      let end: number | null = null;
      const third = row[2];
      if (typeof third === "number" && third < 1000) end = start + third * 86400000;
      else end = toDate(third);
      if (end === null) continue;
      tasks.push({ name, start, end });
    }
    if (tasks.length === 0) throw new Error("No valid tasks found. Ensure Start and End are dates.");

    const minStart = Math.min(...tasks.map((t) => t.start));

    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const helperRow = sel.rowIndex;
    const helperCol = sel.columnIndex + sel.columnCount + 1;
    const helperRange = sheet.getRangeByIndexes(helperRow, helperCol, tasks.length + 1, 3);

    const helperValues: (string | number)[][] = [["Task", "Offset (days)", "Duration (days)"]];
    tasks.forEach((t) => {
      helperValues.push([
        t.name,
        Math.round((t.start - minStart) / 86400000),
        Math.round((t.end - t.start) / 86400000),
      ]);
    });
    helperRange.values = helperValues;
    await ctx.sync();

    const chart = sheet.charts.add(Excel.ChartType.barStacked, helperRange, Excel.ChartSeriesBy.auto);
    chart.name = "SharpCell.gantt." + Math.random().toString(36).slice(2, 8);
    chart.title.text = "Gantt";
    chart.title.format.font.size = 14;
    chart.title.format.font.bold = true;
    chart.title.format.font.name = palette.font;
    try { chart.legend.visible = false; } catch { /* */ }

    chart.load("series/items");
    await ctx.sync();

    const series = chart.series.items;
    if (series[0]) {
      try { series[0].format.fill.clear(); } catch {
        try { series[0].format.fill.setSolidColor("#FFFFFF"); } catch { /* */ }
      }
      try { series[0].format.line.color = "#FFFFFF"; } catch { /* */ }
    }
    if (series[1]) {
      try { series[1].format.fill.setSolidColor(palette.accent); } catch { /* */ }
    }

    chart.left = 60;
    chart.top = 60;
    chart.width = 600;
    chart.height = 320;
    await ctx.sync();

    await BindingRegistry.add({
      chartType: "gantt",
      shapeName: chart.name,
      sheetName: sel.worksheet.name,
      rangeAddress: sel.address,
    });
  });
}

export async function renderGantt(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  await BindingRegistry.update(binding.id, {
    rangeAddress: snap.address,
    sheetName: snap.sheetName,
  });
}
