/*
 * Smart-insert orchestrator. Given the user's current selection and a chart
 * type, this function:
 *   1. Analyses the layout
 *   2. Pivots into a chart-ready helper range if needed
 *   3. Inserts the requested native Excel chart against the right range
 *
 * Used by the task pane's "Smart" tab. The user picks a chart from a grid;
 * SharpCell handles the wrangling.
 */

/* global Excel */

import { activePalette } from "../core/style";
import { BindingRegistry } from "../core/bindings";
import { analyzeLayout, pivotLongToWide, materializePivot, LayoutAnalysis } from "./autoPivot";

export type SmartChartType =
  | "waterfall"
  | "stacked"
  | "stackedBar"
  | "column"
  | "bar"
  | "line"
  | "funnel"
  | "pareto"
  | "treemap"
  | "sunburst"
  | "histogram"
  | "boxWhisker"
  | "pie"
  | "area";

const TYPE_MAP: Record<SmartChartType, Excel.ChartType> = {
  waterfall: Excel.ChartType.waterfall,
  stacked: Excel.ChartType.columnStacked,
  stackedBar: Excel.ChartType.barStacked,
  column: Excel.ChartType.columnClustered,
  bar: Excel.ChartType.barClustered,
  line: Excel.ChartType.line,
  funnel: Excel.ChartType.funnel,
  pareto: Excel.ChartType.pareto,
  treemap: Excel.ChartType.treemap,
  sunburst: Excel.ChartType.sunburst,
  histogram: Excel.ChartType.histogram,
  boxWhisker: Excel.ChartType.boxwhisker,
  pie: Excel.ChartType.pie,
  area: Excel.ChartType.area,
};

const TITLE_MAP: Record<SmartChartType, string> = {
  waterfall: "Waterfall",
  stacked: "Stacked",
  stackedBar: "Stacked Bar",
  column: "Column",
  bar: "Bar",
  line: "Line",
  funnel: "Funnel",
  pareto: "Pareto",
  treemap: "Treemap",
  sunburst: "Sunburst",
  histogram: "Histogram",
  boxWhisker: "Box & Whisker",
  pie: "Pie",
  area: "Area",
};

export interface SmartInsertResult {
  chartName: string;
  usedPivot: boolean;
  layout: LayoutAnalysis;
}

export async function smartInsert(chartType: SmartChartType): Promise<SmartInsertResult> {
  const palette = activePalette();

  return Excel.run(async (ctx) => {
    const sel = ctx.workbook.getSelectedRange();
    sel.load([
      "address",
      "values",
      "rowCount",
      "columnCount",
      "rowIndex",
      "columnIndex",
      "worksheet/name",
    ]);
    await ctx.sync();

    // Convert Excel Range to a snapshot for the analyzer.
    const snap = {
      address: sel.address,
      sheetName: sel.worksheet.name,
      values: sel.values,
      rowCount: sel.rowCount,
      columnCount: sel.columnCount,
    };
    const layout = analyzeLayout(snap);

    // Decide whether to pivot.
    let chartRange: Excel.Range = sel;
    let usedPivot = false;
    if (layout.kind === "long" && layout.suggestedPivot) {
      const result = pivotLongToWide(snap, layout.suggestedPivot);
      chartRange = await materializePivot(ctx, sel, result, "SharpCell pivot (auto)");
      usedPivot = true;
    } else if (layout.kind === "unknown") {
      throw new Error(
        "SharpCell can't auto-detect this layout. Try a Label + Value pair, a Category + multiple series, or a 3-column long format (Key1, Key2, Value)."
      );
    }

    // Insert the chart.
    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const chart = sheet.charts.add(TYPE_MAP[chartType], chartRange, Excel.ChartSeriesBy.auto);
    chart.name = "SharpCell." + chartType + "." + Math.random().toString(36).slice(2, 8);
    chart.title.text = TITLE_MAP[chartType];
    chart.title.format.font.size = 14;
    chart.title.format.font.bold = true;
    chart.title.format.font.name = palette.font;

    // Tweak per chart type.
    if (chartType === "stacked" || chartType === "stackedBar") {
      try {
        chart.load("series/items");
        await ctx.sync();
        const series = chart.series.items;
        const top = series[series.length - 1];
        if (top) {
          top.dataLabels.showValue = true;
          top.dataLabels.position = Excel.ChartDataLabelPosition.outsideEnd;
          top.dataLabels.format.font.bold = true;
        }
      } catch {
        // older host
      }
    }

    chart.left = chartRange.left ?? 60;
    chart.top = 60;
    chart.width = 520;
    chart.height = 340;
    await ctx.sync();

    await BindingRegistry.add({
      chartType: chartType as never,
      shapeName: chart.name,
      sheetName: chartRange.worksheet.name,
      rangeAddress: chartRange.address,
    });

    return { chartName: chart.name, usedPivot, layout };
  });
}

/** Analyze the user's current selection. Used by the task pane preview. */
export async function analyzeCurrentSelection(): Promise<LayoutAnalysis> {
  return Excel.run(async (ctx) => {
    const sel = ctx.workbook.getSelectedRange();
    sel.load(["values", "rowCount", "columnCount", "address", "worksheet/name"]);
    await ctx.sync();
    return analyzeLayout({
      address: sel.address,
      sheetName: sel.worksheet.name,
      values: sel.values,
      rowCount: sel.rowCount,
      columnCount: sel.columnCount,
    });
  });
}

