/*
 * Waterfall chart — uses Excel's native waterfall chart type
 * (Excel.ChartType.waterfall). Microsoft added this to Excel in 2016, and
 * because it is a first-class chart, every Excel formatting feature works on
 * it: click a bar, recolor it via the Format pane, drag the chart, resize,
 * change source data, all native.
 *
 * Expected input range (the user's selection):
 *   [Label]   [Value]
 *   "Start"    100
 *   "Q1"        25
 *   "Q2"       -10
 *   "End"       -        (blank cell = Excel treats as a Total/subtotal bar)
 *
 * The header row is required so Excel uses it for the series name.
 */

/* global Excel */

import { activePalette } from "../core/style";
import { BindingRegistry, RegisteredBinding } from "../core/bindings";
import { readActiveSelection, RangeSnapshot } from "../core/data";

export async function insertWaterfall(): Promise<void> {
  const palette = activePalette();
  await Excel.run(async (ctx) => {
    const range = ctx.workbook.getSelectedRange();
    range.load(["address", "columnCount", "rowCount", "worksheet/name"]);
    await ctx.sync();

    if (range.columnCount < 2) {
      throw new Error("Select at least 2 columns: Label, Value.");
    }

    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const chart = sheet.charts.add(
      Excel.ChartType.waterfall,
      range,
      Excel.ChartSeriesBy.auto
    );
    chart.name = "SharpCell.waterfall." + Math.random().toString(36).slice(2, 8);
    chart.title.text = "Waterfall";
    chart.title.format.font.size = 14;
    chart.title.format.font.bold = true;
    chart.title.format.font.name = palette.font;
    try {
      chart.legend.visible = false;
    } catch {
      // legend may not exist on some hosts
    }

    // Apply palette colors to the series. Excel's waterfall chart exposes one
    // series with three "point" categories (increase, decrease, total); the
    // exact API for setting these per-category colors differs across hosts,
    // so we attempt it but don't fail if not supported.
    try {
      chart.load("series/items");
      await ctx.sync();
      const series = chart.series.items[0];
      if (series) {
        series.format.fill.setSolidColor(palette.positive);
      }
    } catch {
      // older host: skip
    }

    chart.left = 60;
    chart.top = 60;
    chart.width = 480;
    chart.height = 320;

    await ctx.sync();

    await BindingRegistry.add({
      chartType: "waterfall",
      shapeName: chart.name,
      sheetName: range.worksheet.name,
      rangeAddress: range.address,
    });
  });
}

/**
 * Refresh: the native chart auto-tracks its source range, so refresh is a
 * no-op unless the range itself moved. We just update the binding record.
 */
export async function renderWaterfall(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  await BindingRegistry.update(binding.id, {
    rangeAddress: snap.address,
    sheetName: snap.sheetName,
  });
}

export async function renderNativeWaterfall(): Promise<void> {
  // Retained as a stub; new code path lives in insertWaterfall.
  await insertWaterfall();
}

// Avoid unused-import warning in upstream callers
void readActiveSelection;
