/*
 * Mekko (Marimekko) chart — stacked columns where column WIDTH is also data-driven.
 *
 * Input range layout:
 *   [Segment]    [Series1] [Series2] [Series3] ...
 *   "Region A"    120       80        50
 *   "Region B"    200       40        30
 *   ...
 *
 * Width of each column = sum of that row. Within each column, series are
 * stacked proportionally so the chart shows both share-of-segment and
 * share-of-total in one view.
 */

import { readActiveSelection, parseTable, RangeSnapshot } from "../core/data";
import { activePalette } from "../core/style";
import {
  openSvg,
  closeSvg,
  title,
  rect,
  text,
  formatNumber,
  DEFAULT_SIZE,
  DEFAULT_MARGINS,
  seriesColor,
} from "./svgPrimitives";
import { upsertSvgShape } from "./svgHost";
import { RegisteredBinding } from "../core/bindings";

export function renderMekkoSvg(snap: RangeSnapshot, opts?: { titleText?: string }): string {
  const parsed = parseTable(snap);
  const { categories, series, matrix, totals } = parsed;
  const grandTotal = totals.row.reduce((s, v) => s + v, 0);
  if (grandTotal <= 0) throw new Error("Mekko needs positive totals.");

  const palette = activePalette();
  const { width, height } = DEFAULT_SIZE;
  const m = { ...DEFAULT_MARGINS };
  const plotW = width - m.left - m.right;
  const plotH = height - m.top - m.bottom;

  let svg = openSvg();
  svg += title(opts?.titleText ?? "Mekko", { width, height });

  // Compute column x positions based on row totals
  let xCursor = m.left;
  const colXs: { x: number; w: number }[] = [];
  categories.forEach((_, i) => {
    const w = (totals.row[i] / grandTotal) * plotW;
    colXs.push({ x: xCursor, w });
    xCursor += w;
  });

  // For each column, stack series proportionally to column total
  categories.forEach((cat, i) => {
    const col = colXs[i];
    const colTotal = totals.row[i] || 1;
    let yCursor = m.top;
    matrix[i].forEach((v, sIdx) => {
      const portion = v / colTotal;
      const h = portion * plotH;
      const color = seriesColor(sIdx, palette);
      svg += rect(col.x, yCursor, col.w, h, color, { stroke: "white", strokeWidth: 1 });
      if (h > 14 && col.w > 36) {
        svg += text(col.x + col.w / 2, yCursor + h / 2 + 3, formatNumber(v), {
          fill: "white",
          weight: "600",
        });
      }
      yCursor += h;
    });
    // column label below
    svg += text(col.x + col.w / 2, m.top + plotH + 16, cat, { size: 10 });
    svg += text(col.x + col.w / 2, m.top + plotH + 30, formatNumber(totals.row[i]), {
      size: 10,
      fill: "#666",
      weight: "600",
    });
  });

  // Legend
  const legendY = m.top + plotH + 46;
  let lx = m.left;
  series.forEach((s, i) => {
    svg += rect(lx, legendY, 10, 10, seriesColor(i, palette));
    svg += text(lx + 14, legendY + 9, s, { anchor: "start", size: 10 });
    lx += 14 + s.length * 6 + 16;
  });

  svg += closeSvg();
  return svg;
}

export async function insertMekko(): Promise<void> {
  const snap = await readActiveSelection();
  const svg = renderMekkoSvg(snap);
  await upsertSvgShape(svg, "mekko", snap);
}

export async function renderMekko(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  const svg = renderMekkoSvg(snap);
  await upsertSvgShape(svg, "mekko", snap, binding);
}

