/*
 * Charts are rendered as SVG, then rasterized to PNG and inserted into the
 * worksheet as a picture Shape. PNG is used because Excel on the web does not
 * reliably accept SVG via shapes.addImage; PNG works across desktop, Mac, and
 * web.
 *
 * Each shape carries a name like "SharpCell.<chartType>.<short-id>" so the
 * binding registry can find it again and replace it on refresh.
 */

/* global Excel, document, Image, btoa, unescape, encodeURIComponent */

import { BindingRegistry, ChartType, RegisteredBinding } from "../core/bindings";
import { RangeSnapshot } from "../core/data";

const SHAPE_PREFIX = "SharpCell";

export function makeShapeName(chartType: ChartType): string {
  const stamp = Math.random().toString(36).slice(2, 8);
  return `${SHAPE_PREFIX}.${chartType}.${stamp}`;
}

export async function upsertSvgShape(
  svg: string,
  chartType: ChartType,
  source: RangeSnapshot,
  existing?: RegisteredBinding
): Promise<RegisteredBinding> {
  const shapeName = existing?.shapeName ?? makeShapeName(chartType);

  // Rasterize SVG -> PNG -> base64 in the add-in's webview.
  const pngBase64 = await svgToPngBase64(svg, 720, 440);

  return Excel.run(async (ctx) => {
    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const shapes = sheet.shapes;
    shapes.load("items/name");
    await ctx.sync();

    let priorLeft = 40;
    let priorTop = 40;
    let priorWidth = 480;
    let priorHeight = 300;
    const prior = shapes.items.find((s) => s.name === shapeName);
    if (prior) {
      prior.load(["left", "top", "width", "height"]);
      await ctx.sync();
      priorLeft = prior.left;
      priorTop = prior.top;
      priorWidth = prior.width;
      priorHeight = prior.height;
      prior.delete();
      await ctx.sync();
    }

    const image = shapes.addImage(pngBase64);
    image.name = shapeName;
    image.left = priorLeft;
    image.top = priorTop;
    image.width = priorWidth;
    image.height = priorHeight;
    await ctx.sync();

    if (existing) {
      await BindingRegistry.update(existing.id, {
        rangeAddress: source.address,
        sheetName: source.sheetName,
      });
      return existing;
    }
    return BindingRegistry.add({
      chartType,
      shapeName,
      sheetName: source.sheetName,
      rangeAddress: source.address,
    });
  });
}

/**
 * Convert an SVG string to a base64-encoded PNG, sized to the given dimensions.
 * Uses the browser canvas API. Office add-ins run inside a Chromium-based webview
 * with DOM, so this works in desktop, Mac, and web Excel.
 */
export function svgToPngBase64(svg: string, width: number, height: number): Promise<string> {
  return new Promise((resolve, reject) => {
    try {
      const svgBase64 = btoa(unescape(encodeURIComponent(svg)));
      const dataUrl = `data:image/svg+xml;base64,${svgBase64}`;

      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => {
        try {
          const canvas = document.createElement("canvas");
          const scale = 2; // 2x for crisper rendering
          canvas.width = width * scale;
          canvas.height = height * scale;
          const ctx = canvas.getContext("2d");
          if (!ctx) return reject(new Error("Canvas 2D context unavailable"));
          ctx.fillStyle = "#ffffff";
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const pngDataUrl = canvas.toDataURL("image/png");
          const base64 = pngDataUrl.split(",", 2)[1];
          if (!base64) return reject(new Error("PNG rasterization produced empty output"));
          resolve(base64);
        } catch (e) {
          reject(e instanceof Error ? e : new Error(String(e)));
        }
      };
      img.onerror = () =>
        reject(new Error("SVG decode failed — invalid markup or unsupported element"));
      img.src = dataUrl;
    } catch (e) {
      reject(e instanceof Error ? e : new Error(String(e)));
    }
  });
}
