import * as React from "react";
import { useStatus } from "../StatusBar";
import {
  analyzeCurrentSelection,
  smartInsert,
  CHART_OPTIONS,
  SmartChartType,
} from "../../charts/smartInsert";
import { LayoutAnalysis } from "../../charts/autoPivot";

export const SmartPanel: React.FC = () => {
  const { setMessage } = useStatus();
  const [layout, setLayout] = React.useState<LayoutAnalysis | null>(null);
  const [busy, setBusy] = React.useState(false);

  const refreshLayout = React.useCallback(async () => {
    try {
      const l = await analyzeCurrentSelection();
      setLayout(l);
    } catch (e) {
      setMessage("Couldn't read selection: " + (e instanceof Error ? e.message : String(e)));
    }
  }, [setMessage]);

  React.useEffect(() => {
    void refreshLayout();
  }, [refreshLayout]);

  const handleInsert = async (type: SmartChartType) => {
    setBusy(true);
    setMessage("Inserting " + type + "...");
    try {
      const result = await smartInsert(type);
      const note = result.usedPivot
        ? "Inserted " + type + ". Data was pivoted automatically — pivot table is below your selection."
        : "Inserted " + type + ".";
      setMessage(note);
      await refreshLayout();
    } catch (e) {
      setMessage("Error: " + (e instanceof Error ? e.message : String(e)));
    } finally {
      setBusy(false);
    }
  };

  const kindColor = (k: LayoutAnalysis["kind"]) =>
    k === "wide-ready"
      ? "#2CA02C"
      : k === "pairs"
        ? "#1F77B4"
        : k === "numeric-only"
          ? "#9467BD"
          : k === "long"
            ? "#FF7F0E"
            : "#D62728";

  // Filter chart options to those that work on the detected layout.
  const supportedFor = (kind: LayoutAnalysis["kind"]): SmartChartType[] => {
    switch (kind) {
      case "pairs":
        return ["waterfall", "funnel", "pareto", "column", "bar", "pie", "line", "area"];
      case "wide-ready":
        return ["stacked", "stackedBar", "column", "bar", "line", "area", "treemap", "sunburst"];
      case "long":
        return ["stacked", "stackedBar", "column", "bar", "line", "area", "treemap", "sunburst"];
      case "numeric-only":
        return ["histogram", "boxWhisker"];
      default:
        return [];
    }
  };
  const supported = layout ? supportedFor(layout.kind) : [];

  return (
    <>
      <section className="sc-section">
        <h2>Selection</h2>
        <button className="sc-btn" onClick={refreshLayout} disabled={busy}>
          Re-detect from current selection
        </button>
        {layout && (
          <div
            style={{
              marginTop: 10,
              padding: 10,
              border: "1px solid var(--sc-border)",
              borderLeft: "4px solid " + kindColor(layout.kind),
              borderRadius: 4,
              background: "var(--sc-hover)",
              fontSize: 12,
            }}
          >
            <div style={{ fontWeight: 600, marginBottom: 4 }}>
              {layout.kind === "unknown" ? "Layout unclear" : layout.kind.toUpperCase()}
            </div>
            <div style={{ color: "var(--sc-muted)" }}>{layout.summary}</div>
            {layout.suggestedPivot && (
              <div style={{ marginTop: 6, color: "#FF7F0E", fontWeight: 500 }}>
                ⤴ Will auto-pivot before inserting
              </div>
            )}
          </div>
        )}
      </section>

      <section className="sc-section">
        <h2>Insert chart</h2>
        {layout && layout.kind !== "unknown" ? (
          <div className="sc-grid">
            {CHART_OPTIONS.filter((c) => supported.includes(c.type)).map((c) => (
              <button
                key={c.type}
                className="sc-card"
                onClick={() => handleInsert(c.type)}
                disabled={busy}
              >
                <span className="label">{c.label}</span>
                <span className="desc">{c.needs}</span>
              </button>
            ))}
          </div>
        ) : (
          <p style={{ fontSize: 12, color: "var(--sc-muted)" }}>
            Select a data range in the worksheet, then click "Re-detect".
          </p>
        )}
      </section>

      <section className="sc-section">
        <h2>Supported layouts</h2>
        <ul style={{ fontSize: 11, color: "var(--sc-muted)", paddingLeft: 18, lineHeight: 1.6 }}>
          <li>
            <strong>Pairs</strong>: 2 cols, Label + Value
          </li>
          <li>
            <strong>Wide-ready</strong>: Category + multiple numeric series
          </li>
          <li>
            <strong>Long</strong>: 3 cols (Key1, Key2, Value) — auto-pivoted
          </li>
          <li>
            <strong>Numeric-only</strong>: 1 column of numbers
          </li>
        </ul>
      </section>
    </>
  );
};
