/*
 * Formatting automation — apply corporate style and clean up chart chrome.
 */

/* global Excel */

import { activePalette } from "./style";

/**
 * Apply the active palette and font to the selected chart (if any).
 * Operates on Excel.Chart objects, not SharpCell-rendered shape charts.
 */
export async function applyCorporateStyle(): Promise<void> {
  const palette = activePalette();
  await Excel.run(async (ctx) => {
    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const charts = sheet.charts;
    charts.load("items/name");
    await ctx.sync();

    // Prefer the selected chart; fall back to the first chart on the sheet.
    const selected = await tryGetSelectedChart(ctx);
    const target = selected ?? charts.items[0];
    if (!target) throw new Error("No chart found on the active sheet.");

    target.load(["series/items"]);
    await ctx.sync();

    target.format.font.name = palette.font;
    target.format.font.color = "#1A1A1A";
    target.title?.format.font.set({ name: palette.font, size: 14, bold: true });

    target.series.items.forEach((s, i) => {
      const color = palette.colors[i % palette.colors.length];
      s.format.fill.setSolidColor(color);
      try {
        s.format.line.color = color;
      } catch {
        /* line not applicable for some chart types */
      }
    });

    await ctx.sync();
  });
}

/** Strip non-essential chart chrome: gridlines, busy borders, axis lines. */
export async function cleanupChart(): Promise<void> {
  await Excel.run(async (ctx) => {
    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const selected = await tryGetSelectedChart(ctx);
    const charts = sheet.charts;
    charts.load("items/name");
    await ctx.sync();
    const target = selected ?? charts.items[0];
    if (!target) throw new Error("No chart found on the active sheet.");

    target.load(["axes"]);
    await ctx.sync();

    // Hide gridlines on value axis
    try {
      const valueAxis = target.axes.valueAxis;
      valueAxis.majorGridlines.visible = false;
      valueAxis.minorGridlines.visible = false;
      valueAxis.format.line.color = "#CCCCCC";
    } catch {
      /* axis missing on chart type */
    }

    try {
      const categoryAxis = target.axes.categoryAxis;
      categoryAxis.format.line.color = "#CCCCCC";
    } catch {
      /* ignore */
    }

    target.legend.position = Excel.ChartLegendPosition.bottom;
    target.legend.format.font.size = 10;

    await ctx.sync();
  });
}

async function tryGetSelectedChart(ctx: Excel.RequestContext): Promise<Excel.Chart | null> {
  // There is no first-class API for "currently selected chart" — we approximate by
  // pulling the active object name from the workbook. If the user clicked a chart,
  // its name is exposed via getActiveChart() in newer Excel builds.
  try {
    // getActiveChart is available in recent Excel builds; cast to any defensively
    const c = (ctx.workbook as unknown as { getActiveChart?: () => Excel.Chart }).getActiveChart?.();
    if (c) {
      c.load("name");
      await ctx.sync();
      return c;
    }
  } catch {
    // not available
  }
  return null;
}
