import * as React from "react";

interface StatusContextValue {
  message: string;
  setMessage: (msg: string) => void;
}

const StatusContext = React.createContext<StatusContextValue>({
  message: "",
  setMessage: () => undefined,
});

export const useStatus = () => React.useContext(StatusContext);

export const StatusProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [message, setMessage] = React.useState("Ready.");
  return <StatusContext.Provider value={{ message, setMessage }}>{children}</StatusContext.Provider>;
};

export const StatusBar: React.FC = () => {
  const { message } = useStatus();
  return <div className="sc-status">{message}</div>;
};
