import * as React from "react";
import { SmartPanel } from "./panels/SmartPanel";
import { ChartsPanel } from "./panels/ChartsPanel";
import { BindingsPanel } from "./panels/BindingsPanel";
import { StylePanel } from "./panels/StylePanel";
import { StatusProvider, StatusBar } from "./StatusBar";

type Tab = "smart" | "charts" | "bindings" | "style";

export const App: React.FC = () => {
  const [tab, setTab] = React.useState<Tab>("smart");

  return (
    <StatusProvider>
      <div className="sc-app">
        <header className="sc-header">
          <h1>SharpCell</h1>
          <p>Native charts, smart data wrangling, corporate formatting.</p>
        </header>

        <nav className="sc-tabs">
          <button className={`sc-tab ${tab === "smart" ? "active" : ""}`} onClick={() => setTab("smart")}>
            Smart
          </button>
          <button className={`sc-tab ${tab === "charts" ? "active" : ""}`} onClick={() => setTab("charts")}>
            Charts
          </button>
          <button className={`sc-tab ${tab === "bindings" ? "active" : ""}`} onClick={() => setTab("bindings")}>
            Bindings
          </button>
          <button className={`sc-tab ${tab === "style" ? "active" : ""}`} onClick={() => setTab("style")}>
            Style
          </button>
        </nav>

        <main className="sc-body">
          {tab === "smart" && <SmartPanel />}
          {tab === "charts" && <ChartsPanel />}
          {tab === "bindings" && <BindingsPanel />}
          {tab === "style" && <StylePanel />}
        </main>

        <StatusBar />
      </div>
    </StatusProvider>
  );
};
