/*
 * Auto-pivot: detect the shape of a user's selection and prepare a
 * chart-ready range. Solves the "my data is in the wrong shape" problem
 * that ThinkCell users hit constantly.
 *
 * Recognised layouts:
 *   1. WIDE-READY    [Category, Series1, Series2, ...]  — first col labels,
 *                    rest numeric. Insertable directly into any native chart.
 *   2. LONG          [Category1, Category2, Value]      — 3 cols, first two
 *                    text/keys, last numeric. Needs a pivot to chart.
 *   3. PAIRS         [Label, Value]                     — 2 cols, ready for
 *                    waterfall/funnel/pareto.
 *   4. NUMERIC_ONLY  [Value]                            — 1 col of numbers,
 *                    ready for histogram / box & whisker.
 *   5. UNKNOWN       — anything else; user must pivot manually.
 */

/* global Excel */

import { RangeSnapshot } from "../core/data";

export type LayoutKind = "wide-ready" | "long" | "pairs" | "numeric-only" | "unknown";

export interface LayoutAnalysis {
  kind: LayoutKind;
  rowCount: number;
  columnCount: number;
  hasHeaderRow: boolean;
  /** Index of the label column (usually 0). undefined for numeric-only. */
  labelCol?: number;
  /** Indexes of columns that contain numeric data. */
  numericCols: number[];
  /** Indexes of columns that contain text/category data. */
  textCols: number[];
  /** For LONG layout: suggested pivot { rowKey, colKey, valueCol } */
  suggestedPivot?: {
    rowKey: number;
    colKey: number;
    valueCol: number;
  };
  /** Human-readable summary, shown in the task pane. */
  summary: string;
}

function isNumericLike(v: unknown): boolean {
  if (typeof v === "number") return Number.isFinite(v);
  if (typeof v === "string") {
    const s = v.trim().replace(/[$,%\s]/g, "");
    if (s === "") return false;
    const n = Number(s);
    return Number.isFinite(n);
  }
  return false;
}

function looksLikeHeader(row: unknown[], rest: unknown[][]): boolean {
  // Header heuristic: row[0..] are mostly text; corresponding cells below are mostly numeric or different from row.
  const textShare = row.filter((c) => typeof c === "string" && c !== "").length / row.length;
  if (textShare < 0.5) return false;
  if (rest.length === 0) return true;
  let restNumericShare = 0;
  for (let c = 1; c < row.length; c++) {
    let n = 0;
    for (const r of rest) if (isNumericLike(r[c])) n++;
    restNumericShare += n / rest.length;
  }
  restNumericShare /= Math.max(1, row.length - 1);
  return restNumericShare > 0.5;
}

export function analyzeLayout(snap: RangeSnapshot): LayoutAnalysis {
  const { values, rowCount, columnCount } = snap;
  if (rowCount === 0 || columnCount === 0) {
    return {
      kind: "unknown",
      rowCount,
      columnCount,
      hasHeaderRow: false,
      numericCols: [],
      textCols: [],
      summary: "Empty selection.",
    };
  }

  // Detect header row
  const hasHeader = rowCount > 1 && looksLikeHeader(values[0], values.slice(1));
  const dataRows = hasHeader ? values.slice(1) : values;

  // Per-column type tally
  const numericCols: number[] = [];
  const textCols: number[] = [];
  for (let c = 0; c < columnCount; c++) {
    let numeric = 0;
    let text = 0;
    for (const r of dataRows) {
      const v = r[c];
      if (v == null || v === "") continue;
      if (isNumericLike(v)) numeric++;
      else if (typeof v === "string") text++;
    }
    if (numeric > text) numericCols.push(c);
    else if (text > 0) textCols.push(c);
  }

  const labelCol = textCols[0];

  // Classify
  if (columnCount === 1 && numericCols.length === 1) {
    return {
      kind: "numeric-only",
      rowCount,
      columnCount,
      hasHeaderRow: hasHeader,
      numericCols,
      textCols,
      summary: `1 numeric column × ${dataRows.length} values — ready for histogram or box & whisker.`,
    };
  }

  if (columnCount === 2 && numericCols.includes(1) && textCols.includes(0)) {
    return {
      kind: "pairs",
      rowCount,
      columnCount,
      hasHeaderRow: hasHeader,
      labelCol: 0,
      numericCols,
      textCols,
      summary: `Label + Value (${dataRows.length} rows) — ready for waterfall, funnel, pareto.`,
    };
  }

  if (columnCount >= 3 && textCols.length === 2 && numericCols.length === 1) {
    // LONG: two key columns + one value column → suggest pivot
    return {
      kind: "long",
      rowCount,
      columnCount,
      hasHeaderRow: hasHeader,
      labelCol,
      numericCols,
      textCols,
      suggestedPivot: { rowKey: textCols[0], colKey: textCols[1], valueCol: numericCols[0] },
      summary: `Long format (${textCols.length} keys + 1 value). Pivot recommended.`,
    };
  }

  if (columnCount >= 2 && textCols.includes(0) && numericCols.length >= 1 && numericCols.every((c) => c > 0)) {
    return {
      kind: "wide-ready",
      rowCount,
      columnCount,
      hasHeaderRow: hasHeader,
      labelCol: 0,
      numericCols,
      textCols,
      summary: `Category + ${numericCols.length} series × ${dataRows.length} rows — chart-ready.`,
    };
  }

  return {
    kind: "unknown",
    rowCount,
    columnCount,
    hasHeaderRow: hasHeader,
    labelCol,
    numericCols,
    textCols,
    summary: `Mixed layout — ${textCols.length} text col(s), ${numericCols.length} numeric col(s).`,
  };
}

export interface PivotPlan {
  rowKey: number;
  colKey: number;
  valueCol: number;
  /** Aggregation function for collisions. */
  agg?: "sum" | "avg" | "first";
}

export interface PivotResult {
  /** 2D values to write into a helper range: [headerRow, ...dataRows]. */
  values: (string | number)[][];
  /** Row count (incl. header). */
  rows: number;
  /** Column count. */
  cols: number;
}

/**
 * Pivot a long-format snapshot into wide format.
 * E.g. [Company, Year, EBITDA] becomes Company × Year matrix of EBITDA.
 */
export function pivotLongToWide(snap: RangeSnapshot, plan: PivotPlan): PivotResult {
  const dataStart = looksLikeHeader(snap.values[0], snap.values.slice(1)) ? 1 : 0;
  const rows = snap.values.slice(dataStart);

  const rowKeys: string[] = [];
  const colKeys: string[] = [];
  const buckets: Map<string, Map<string, { sum: number; count: number; first?: number }>> = new Map();

  const agg = plan.agg ?? "sum";

  for (const r of rows) {
    const rk = String(r[plan.rowKey] ?? "");
    const ck = String(r[plan.colKey] ?? "");
    const vRaw = r[plan.valueCol];
    if (rk === "" || ck === "") continue;
    let v: number;
    if (typeof vRaw === "number") v = vRaw;
    else if (typeof vRaw === "string") {
      const s = vRaw.trim().replace(/[$,%\s]/g, "");
      v = Number(s);
    } else v = NaN;
    if (!Number.isFinite(v)) continue;

    if (!rowKeys.includes(rk)) rowKeys.push(rk);
    if (!colKeys.includes(ck)) colKeys.push(ck);
    if (!buckets.has(rk)) buckets.set(rk, new Map());
    const inner = buckets.get(rk)!;
    if (!inner.has(ck)) inner.set(ck, { sum: 0, count: 0 });
    const cell = inner.get(ck)!;
    cell.sum += v;
    cell.count += 1;
    if (cell.first === undefined) cell.first = v;
  }

  // Sort column keys if they look like years/dates/numbers
  colKeys.sort((a, b) => {
    const na = Number(a);
    const nb = Number(b);
    if (Number.isFinite(na) && Number.isFinite(nb)) return na - nb;
    return a.localeCompare(b);
  });

  const header: (string | number)[] = ["", ...colKeys];
  const out: (string | number)[][] = [header];
  for (const rk of rowKeys) {
    const row: (string | number)[] = [rk];
    const inner = buckets.get(rk);
    for (const ck of colKeys) {
      const cell = inner?.get(ck);
      if (!cell) {
        row.push("");
        continue;
      }
      const v = agg === "avg" ? cell.sum / cell.count : agg === "first" ? cell.first! : cell.sum;
      row.push(v);
    }
    out.push(row);
  }

  return { values: out, rows: out.length, cols: header.length };
}

/**
 * Write a pivot result into an empty area adjacent to the user's selection
 * and return the resulting range so a chart can use it as source.
 */
export async function materializePivot(
  ctx: Excel.RequestContext,
  source: Excel.Range,
  pivotResult: PivotResult,
  label = "SharpCell pivot"
): Promise<Excel.Range> {
  source.load(["rowIndex", "columnIndex", "rowCount", "columnCount", "worksheet/name"]);
  await ctx.sync();

  const sheet = source.worksheet;
  // Place helper 2 rows below the source.
  const startRow = source.rowIndex + source.rowCount + 2;
  const startCol = source.columnIndex;

  // Title row: helps user understand what this block is.
  const titleRange = sheet.getRangeByIndexes(startRow, startCol, 1, 1);
  titleRange.values = [[label]];
  titleRange.format.font.bold = true;
  titleRange.format.font.italic = true;

  const dataRange = sheet.getRangeByIndexes(
    startRow + 1,
    startCol,
    pivotResult.rows,
    pivotResult.cols
  );
  dataRange.values = pivotResult.values;
  await ctx.sync();
  return dataRange;
}
